mapper.select:
SELECT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, e.employee_tier AS authorTier, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.created_at AS createdAt, ka.is_deleted AS deleted, EXISTS( SELECT 1 FROM knowledge_bookmark kb WHERE kb.article_id = ka.article_id AND kb.employee_id = #{requesterId} ) AS bookmarked FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id WHERE 1 = 1
AND ka.is_deleted = false
AND ( ka.author_id = #{requesterId} OR ka.article_status = 'APPROVED' )
AND ka.article_status != 'DRAFT'
AND ka.article_category = #{category}
AND ka.article_status = #{articleStatus}
AND ka.article_id = #{articleIdKeyword}
AND e.employee_name LIKE CONCAT('%', #{keyword}, '%')
AND ka.article_title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ka.view_count DESC
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT DISTINCT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.created_at AS createdAt FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id LEFT JOIN knowledge_article_tag kat ON ka.article_id = kat.article_id LEFT JOIN knowledge_tag kt ON kat.tag_id = kt.tag_id WHERE ka.article_status = 'APPROVED' AND ka.is_deleted = false AND (
ka.article_category IN
#{category}
OR
(
kt.tag_name LIKE CONCAT('%', #{keyword}, '%')
)
) ORDER BY ka.view_count DESC, ka.approved_at DESC, ka.article_id DESC LIMIT #{limit}

SELECT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, e.employee_tier AS authorTier, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.approved_by AS approverId, approver.employee_name AS approverName, ka.article_approval_opinion AS articleApprovalOpinion, ka.created_at AS createdAt, ka.updated_at AS updatedAt FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id LEFT JOIN employee approver ON ka.approved_by = approver.employee_id WHERE ka.is_deleted = false AND ka.article_status = 'PENDING'
AND ka.article_category = #{category}
AND ka.article_id = #{articleIdKeyword}
AND e.employee_name LIKE CONCAT('%', #{keyword}, '%')
AND ka.article_title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ka.view_count DESC
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT ka.article_id AS articleId, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.equipment_id AS equipmentId, eq.equipment_name AS equipmentName, ka.article_content AS articleContent, ka.article_rejection_reason AS articleRejectionReason, ka.article_deletion_reason AS articleDeletionReason, ka.view_count AS viewCount, 0 AS commentCount, ( SELECT COUNT(*) FROM knowledge_edit_history keh WHERE keh.article_id = ka.article_id ) AS reuseCount, ka.is_deleted AS deleted, ka.created_at AS createdAt, ka.updated_at AS updatedAt FROM knowledge_article ka LEFT JOIN equipment eq ON ka.equipment_id = eq.equipment_id WHERE ka.author_id = #{authorId}
AND ka.article_status = #{request.status}
ORDER BY ka.created_at DESC
LIMIT #{request.size} OFFSET #{request.offset}
